import java.util.ArrayList;
import java.util.List;
import java.util.Optional;
import java.util.Set;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Compare;
import org.eclipse.rdf4j.query.algebra.Filter;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.LeftJoin;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinOrderPlanner;
import org.junit.jupiter.api.Test;

class LmdbSketchJoinOptimizerTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void reordersJoinSegmentsUsingJoinOrderPlanner() {
		StatementPattern first = statementPattern("s1", "p1", "o1");
		StatementPattern second = statementPattern("s2", "p2", "o2");
		StatementPattern third = statementPattern("s3", "p3", "o3");
		QueryRoot root = new QueryRoot(new Join(first, new Join(second, third)));
		PlanningStatistics statistics = PlanningStatistics.withPlan(List.of(third, first, second));

		new LmdbSketchJoinOptimizer(statistics, false).optimize(root, null, null);

		assertEquals(List.of(third, first, second), joinArgs(root.getArg()));
		assertEquals(1, statistics.planningAttempts);
	}

	@Test
	void leavesJoinSegmentOrderUnchangedWhenPlannerRejects() {
		StatementPattern first = statementPattern("s1", "p1", "o1");
		StatementPattern second = statementPattern("s2", "p2", "o2");
		StatementPattern third = statementPattern("s3", "p3", "o3");
		QueryRoot root = new QueryRoot(new Join(first, new Join(second, third)));
		PlanningStatistics statistics = PlanningStatistics.rejected();

		new LmdbSketchJoinOptimizer(statistics, false).optimize(root, null, null);

		assertEquals(List.of(first, second, third), joinArgs(root.getArg()));
		assertEquals(1, statistics.planningAttempts);
	}

	@Test
	void movesLeftJoinLocalFilterIntoPlannedLeftSegment() {
		StatementPattern first = statementPattern("s1", "p1", "o1");
		StatementPattern second = statementPattern("s2", "p2", "o2");
		StatementPattern optional = statementPattern("s1", "p3", "opt");
		Filter filter = new Filter(new LeftJoin(new Join(first, second), optional),
				new Compare(new Var("o1"), new Var("o2"), Compare.CompareOp.NE));
		QueryRoot root = new QueryRoot(filter);

		new LmdbSketchJoinOptimizer(PlanningStatistics.rejected(), false).optimize(root, null, null);

		LeftJoin leftJoin = assertInstanceOf(LeftJoin.class, root.getArg());
		Filter movedFilter = assertInstanceOf(Filter.class, leftJoin.getLeftArg());
		assertTrue(containsFilter(leftJoin.getLeftArg()));
		assertEquals(List.of(first, second), joinArgs(movedFilter.getArg()));
	}

	private static StatementPattern statementPattern(String subjectName, String predicateName, String objectName) {
		return new StatementPattern(new Var(subjectName), new Var(predicateName, VF.createIRI("urn:" + predicateName)),
				new Var(objectName));
	}

	private static List<TupleExpr> joinArgs(TupleExpr tupleExpr) {
		List<TupleExpr> args = new ArrayList<>();
		collectJoinArgs(tupleExpr, args);
		return args;
	}

	private static void collectJoinArgs(TupleExpr tupleExpr, List<TupleExpr> args) {
		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			collectJoinArgs(join.getLeftArg(), args);
			collectJoinArgs(join.getRightArg(), args);
			return;
		}
		args.add(tupleExpr);
	}

	private static boolean containsFilter(TupleExpr tupleExpr) {
		if (tupleExpr instanceof Filter) {
			return true;
		}
		if (tupleExpr instanceof Join) {
			Join join = (Join) tupleExpr;
			return containsFilter(join.getLeftArg()) || containsFilter(join.getRightArg());
		}
		return false;
	}

	private static final class PlanningStatistics extends EvaluationStatistics implements JoinOrderPlanner {

		private final List<TupleExpr> plan;
		private int planningAttempts;

		private PlanningStatistics(List<TupleExpr> plan) {
			this.plan = plan;
		}

		static PlanningStatistics withPlan(List<TupleExpr> plan) {
			return new PlanningStatistics(plan);
		}

		static PlanningStatistics rejected() {
			return new PlanningStatistics(null);
		}

		@Override
		public Optional<JoinOrderPlan> planJoinOrder(List<TupleExpr> args, Set<String> initiallyBoundVars,
				Algorithm algorithm) {
			planningAttempts++;
			if (plan == null) {
				return Optional.empty();
			}
			return Optional.of(new JoinOrderPlan(plan, 1.0d, 1.0d));
		}
	}
}
